// Geodesic Lantern — elegant antique faceted dome lantern
// v21: Final polish — prominent raised banding ring, tightened proportions

const { Manifold, CrossSection } = api;

// === PROPORTIONS ===
const RXY    = 13.0;   // outer dome equatorial radius (26mm wide)
const RZ     = 20.0;   // outer dome height (taller than wide)
const WALL_T = 2.0;    // shell wall thickness
const SEGS   = 16;     // low poly = geodesic faceting look

// Dome clipped flat at Z=0 (equatorial cut)
const DOME_BASE_Z = 0.0;

// Inner cavity radii
const IRX = RXY - WALL_T;  // 11mm
const IRZ = RZ  - WALL_T;  // 18mm

// === COLORS ===
const C_FRAME  = '#a87040';   // warm medium bronze
const C_BASE   = '#6b4422';   // dark rich base
const C_FINIAL = '#e6b820';   // bright gold
const C_AMBER  = '#e06800';   // amber glow

// ========================================================
// STEP 1: Outer ellipsoid shell — cut flat at Z=0
// ========================================================
const BIG = RXY * 6;

const outerEgg = Manifold.sphere(1, SEGS).scale([RXY, RXY, RZ]);
const innerEgg = Manifold.sphere(1, SEGS).scale([IRX, IRX, IRZ]);

const aboveZero = Manifold.cube([BIG, BIG, RZ * 2 + 10], false)
  .translate([-BIG/2, -BIG/2, DOME_BASE_Z]);

let domeShell = outerEgg.intersect(aboveZero)
  .subtract(innerEgg.intersect(aboveZero));

// ========================================================
// STEP 2: Window cutters — bidirectional, guaranteed through-wall
// ========================================================
function windowCutter(zAbs, wRadius) {
  const halfLen = RXY + 5.0;
  return Manifold.cylinder(halfLen * 2, wRadius, wRadius, 20, false)
    .rotate([0, 90, 0])
    .translate([-halfLen, 0, zAbs]);
}

function windowRing(zAbs, wRadius, count, offsetDeg) {
  let ring = null;
  for (let i = 0; i < count; i++) {
    const az = (360 / count) * i + offsetDeg;
    const c = windowCutter(zAbs, wRadius).rotate([0, 0, az]);
    ring = ring ? ring.add(c) : c;
  }
  return ring;
}

// Lower ring at Z=6.5, upper at Z=11 (offset 30°)
const lowerRing = windowRing(6.5,  2.6, 6, 0);
const upperRing = windowRing(11.0, 2.1, 6, 30);

domeShell = domeShell.subtract(lowerRing).subtract(upperRing);

// ========================================================
// STEP 3: Raised decorative banding ring between window rows
// A solid torus-like ring that sits on the dome surface at Z=8.75
// (midpoint between lower and upper window rings)
// ========================================================
const BAND_Z      = 8.75;
// At Z=8.75, dome outer radius ≈ RXY * sqrt(1 - (8.75/RZ)^2)
const bandDomeFrac = 8.75 / RZ;
const bandDomeR   = RXY * Math.sqrt(1 - bandDomeFrac * bandDomeFrac); // ≈ 10.7mm

// Raised ring: annular disc, outer R = bandDomeR + 0.8, inner = bandDomeR - 0.6
// Height = 1.8mm — visible as a proud horizontal band
const BAND_RO = bandDomeR + 0.8;
const BAND_RI = bandDomeR - 0.5;
const BAND_H  = 1.8;
const bandRing = CrossSection.circle(BAND_RO, 32)
  .subtract(CrossSection.circle(BAND_RI, 32))
  .extrude(BAND_H)
  .translate([0, 0, BAND_Z - BAND_H / 2]);

// Add banding ring to the frame (same bronze color)
domeShell = domeShell.add(bandRing);

const framePart = api.label(domeShell, 'frame', { color: C_FRAME });

// ========================================================
// STEP 4: Amber inner sphere — solid core
// ========================================================
const amberSphere = Manifold.sphere(1, 48)
  .scale([IRX - 0.4, IRX - 0.4, IRZ - 0.4])
  .intersect(aboveZero);

const amberPart = api.label(amberSphere, 'glow', { color: C_AMBER });

// ========================================================
// STEP 5: Hexagonal base + collar
// ========================================================
const BASE_H = 3.5;
const BASE_R = RXY + 1.2;
const BASE_Z = DOME_BASE_Z - BASE_H;

const hexBase = CrossSection.circle(BASE_R, 6)
  .extrude(BASE_H)
  .translate([0, 0, BASE_Z]);

const COLL_RO = RXY + 0.6;
const COLL_RI = RXY - 1.0;
const COLL_H  = 1.5;
const collar = CrossSection.circle(COLL_RO, 24)
  .subtract(CrossSection.circle(COLL_RI, 24))
  .extrude(COLL_H)
  .translate([0, 0, DOME_BASE_Z - COLL_H]);

const basePart = api.label(hexBase.add(collar), 'base', { color: C_BASE });

// ========================================================
// STEP 6: Gold finial
// ========================================================
const APEX_Z = RZ;

const finStem  = Manifold.cylinder(3.5, 1.2, 1.2, 16)
  .translate([0, 0, APEX_Z - 1.0]);

const BEAD_R   = 2.0;
const BEAD_Z   = APEX_Z + 2.5;
const finBead  = Manifold.sphere(BEAD_R, 18)
  .translate([0, 0, BEAD_Z]);

const SPIRE_Z  = BEAD_Z + BEAD_R * 0.9;
const finSpire = Manifold.cylinder(12.0, BEAD_R * 0.6, 0.2, 16)
  .translate([0, 0, SPIRE_Z]);

const finialPart = api.label(
  finStem.add(finBead).add(finSpire),
  'finial', { color: C_FINIAL }
);

// ========================================================
// STEP 7: Assemble
// ========================================================
return framePart.add(amberPart).add(basePart).add(finialPart);
